-- Create "settings" table
CREATE TABLE "public"."settings" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "key" character varying NOT NULL,
  "value" text NOT NULL,
  "description" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "settings_key_key" to table: "settings"
CREATE UNIQUE INDEX "settings_key_key" ON "public"."settings" ("key");
-- Create "alert_rules" table
CREATE TABLE "public"."alert_rules" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "description" character varying NULL,
  "condition" jsonb NULL,
  "actions" jsonb NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create "alerts" table
CREATE TABLE "public"."alerts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "severity" character varying NOT NULL DEFAULT 'medium',
  "title" character varying NOT NULL,
  "type" character varying NOT NULL DEFAULT 'security',
  "status" character varying NOT NULL DEFAULT 'open',
  "device_id" character varying NULL,
  "user_id" bigint NULL,
  "details" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "acknowledged_at" timestamptz NULL,
  "resolved_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create "applications" table
CREATE TABLE "public"."applications" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "bundle_id" character varying NOT NULL,
  "platform" character varying NOT NULL,
  "type" character varying NOT NULL DEFAULT 'app_store',
  "description" character varying NULL,
  "icon_url" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "applications_bundle_id_key" to table: "applications"
CREATE UNIQUE INDEX "applications_bundle_id_key" ON "public"."applications" ("bundle_id");
-- Create "app_versions" table
CREATE TABLE "public"."app_versions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "version" character varying NOT NULL,
  "build_number" character varying NOT NULL,
  "minimum_os_version" character varying NULL,
  "file_url" character varying NULL,
  "size" bigint NULL,
  "metadata" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "application_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "app_versions_applications_versions" FOREIGN KEY ("application_id") REFERENCES "public"."applications" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create "app_deployments" table
CREATE TABLE "public"."app_deployments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "target_type" character varying NOT NULL,
  "target_id" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'pending',
  "error_message" character varying NULL,
  "installed_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "app_version_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "app_deployments_app_versions_deployments" FOREIGN KEY ("app_version_id") REFERENCES "public"."app_versions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create "device_groups" table
CREATE TABLE "public"."device_groups" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "description" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Modify "devices" table
ALTER TABLE "public"."devices" ADD COLUMN "platform" character varying NULL DEFAULT 'other', ADD COLUMN "status" character varying NULL DEFAULT 'pending', ADD COLUMN "compliance_status" character varying NULL DEFAULT 'unknown', ADD COLUMN "os_version" character varying NULL, ADD COLUMN "device_type" character varying NULL, ADD COLUMN "last_seen" timestamptz NULL, ADD COLUMN "enrolled_at" timestamptz NULL, ADD COLUMN "mac_address" character varying NULL, ADD COLUMN "ip_address" character varying NULL, ADD COLUMN "battery_level" double precision NULL, ADD COLUMN "storage_capacity" bigint NULL, ADD COLUMN "storage_used" bigint NULL, ADD COLUMN "is_jailbroken" boolean NOT NULL DEFAULT false, ADD COLUMN "enrollment_type" character varying NULL DEFAULT 'unknown';
-- Create "device_group_devices" table
CREATE TABLE "public"."device_group_devices" (
  "device_group_id" bigint NOT NULL,
  "device_id" character varying(255) NOT NULL,
  PRIMARY KEY ("device_group_id", "device_id"),
  CONSTRAINT "device_group_devices_device_group_id" FOREIGN KEY ("device_group_id") REFERENCES "public"."device_groups" ("id") ON UPDATE NO ACTION ON DELETE CASCADE,
  CONSTRAINT "device_group_devices_device_id" FOREIGN KEY ("device_id") REFERENCES "public"."devices" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
-- Create "profiles" table
CREATE TABLE "public"."profiles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "platform" character varying NOT NULL DEFAULT 'all',
  "scope" character varying NOT NULL DEFAULT 'device',
  "status" character varying NOT NULL DEFAULT 'draft',
  "security_settings" jsonb NULL,
  "network_config" jsonb NULL,
  "restrictions" jsonb NULL,
  "content_filter" jsonb NULL,
  "compliance_rules" jsonb NULL,
  "payloads" jsonb NULL,
  "version" bigint NOT NULL DEFAULT 1,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "profiles_name_key" to table: "profiles"
CREATE UNIQUE INDEX "profiles_name_key" ON "public"."profiles" ("name");
-- Create "device_group_profiles" table
CREATE TABLE "public"."device_group_profiles" (
  "device_group_id" bigint NOT NULL,
  "profile_id" bigint NOT NULL,
  PRIMARY KEY ("device_group_id", "profile_id"),
  CONSTRAINT "device_group_profiles_device_group_id" FOREIGN KEY ("device_group_id") REFERENCES "public"."device_groups" ("id") ON UPDATE NO ACTION ON DELETE CASCADE,
  CONSTRAINT "device_group_profiles_profile_id" FOREIGN KEY ("profile_id") REFERENCES "public"."profiles" ("id") ON UPDATE NO ACTION ON DELETE CASCADE
);
-- Create "payload_property_definitions" table
CREATE TABLE "public"."payload_property_definitions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "payload_type" character varying NOT NULL,
  "key" character varying NOT NULL,
  "value_type" character varying NOT NULL,
  "default_value" jsonb NULL,
  "enum_values" jsonb NULL,
  "description" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "payloadpropertydefinition_payload_type_key" to table: "payload_property_definitions"
CREATE UNIQUE INDEX "payloadpropertydefinition_payload_type_key" ON "public"."payload_property_definitions" ("payload_type", "key");
-- Create "mobile_configs" table
CREATE TABLE "public"."mobile_configs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "payload_identifier" character varying NOT NULL,
  "payload_type" character varying NOT NULL,
  "payload_display_name" character varying NOT NULL,
  "payload_description" character varying NULL,
  "payload_organization" character varying NULL,
  "payload_uuid" character varying NOT NULL,
  "payload_version" bigint NOT NULL DEFAULT 1,
  "payload_removal_disallowed" boolean NOT NULL DEFAULT false,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "mobile_configs_name_key" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobile_configs_name_key" ON "public"."mobile_configs" ("name");
-- Create index "mobile_configs_payload_identifier_key" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobile_configs_payload_identifier_key" ON "public"."mobile_configs" ("payload_identifier");
-- Create index "mobileconfig_payload_identifier" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobileconfig_payload_identifier" ON "public"."mobile_configs" ("payload_identifier");
-- Create "payloads" table
CREATE TABLE "public"."payloads" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "payload_description" character varying NULL,
  "payload_display_name" character varying NOT NULL,
  "payload_identifier" character varying NOT NULL,
  "payload_organization" character varying NULL,
  "payload_type" character varying NOT NULL,
  "payload_uuid" character varying NOT NULL,
  "payload_version" bigint NOT NULL DEFAULT 1,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "mobile_config_payloads" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "payloads_mobile_configs_payloads" FOREIGN KEY ("mobile_config_payloads") REFERENCES "public"."mobile_configs" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "payloads_payload_identifier_key" to table: "payloads"
CREATE UNIQUE INDEX "payloads_payload_identifier_key" ON "public"."payloads" ("payload_identifier");
-- Create "payload_properties" table
CREATE TABLE "public"."payload_properties" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "value_json" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "payload_properties" bigint NOT NULL,
  "payload_property_definition_properties" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "payload_properties_payload_property_definitions_properties" FOREIGN KEY ("payload_property_definition_properties") REFERENCES "public"."payload_property_definitions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "payload_properties_payloads_properties" FOREIGN KEY ("payload_properties") REFERENCES "public"."payloads" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create "profile_assignments" table
CREATE TABLE "public"."profile_assignments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "target_type" character varying NOT NULL,
  "schedule_type" character varying NOT NULL DEFAULT 'immediate',
  "scheduled_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "profile_id" bigint NOT NULL,
  "device_id" character varying(255) NULL,
  "group_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "profile_assignments_device_groups_group" FOREIGN KEY ("group_id") REFERENCES "public"."device_groups" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "profile_assignments_devices_device" FOREIGN KEY ("device_id") REFERENCES "public"."devices" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "profile_assignments_profiles_assignments" FOREIGN KEY ("profile_id") REFERENCES "public"."profiles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create "profile_deployment_statuses" table
CREATE TABLE "public"."profile_deployment_statuses" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "status" character varying NOT NULL DEFAULT 'pending',
  "error_message" character varying NULL,
  "applied_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "profile_id" bigint NOT NULL,
  "device_id" character varying(255) NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "profile_deployment_statuses_devices_device" FOREIGN KEY ("device_id") REFERENCES "public"."devices" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "profile_deployment_statuses_profiles_deployment_statuses" FOREIGN KEY ("profile_id") REFERENCES "public"."profiles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create "profile_versions" table
CREATE TABLE "public"."profile_versions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "version" bigint NOT NULL,
  "data" jsonb NULL,
  "change_notes" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "profile_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "profile_versions_profiles_versions" FOREIGN KEY ("profile_id") REFERENCES "public"."profiles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
